class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        self._balance = balance  # underscore = "private by convention"

    def deposit(self, amount):
        if amount > 0:
            self._balance += amount

    def withdraw(self, amount):
        if amount > self._balance:
            print("Insufficient funds.")
        else:
            self._balance -= amount

    def get_balance(self):
        return self._balance

account = BankAccount("Alice", 1000)
account.deposit(500)
account.withdraw(200)
print(account.get_balance())  # 1300

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        return f"{self.name} makes a sound."

class Dog(Animal):  # Dog inherits from Animal
    def speak(self):  # override the parent method
        return f"{self.name} says: Woof!"

class Cat(Animal):
    def speak(self):
        return f"{self.name} says: Meow!"

animals = [Dog("Rex"), Cat("Whiskers"), Dog("Buddy")]
for animal in animals:
    print(animal.speak())

class GuideDog(Dog):
    def __init__(self, name, owner):
        super().__init__(name)  # calls Dog's (and Animal's) __init__
        self.owner = owner

    def speak(self):
        parent_speak = super().speak()
        return f"{parent_speak} (Guide dog for {self.owner})"

g = GuideDog("Max", "John")
print(g.speak())
# Max says: Woof! (Guide dog for John)

class Robot:
    def speak(self):
        return "BEEP BOOP"

make_noise(Robot())  # BEEP BOOP — works even though Robot doesn't inherit from Animal

from abc import ABC, abstractmethod

class Shape(ABC):  # abstract base class — cannot be instantiated directly
    @abstractmethod
    def area(self):
        pass  # subclasses must implement this

    @abstractmethod
    def perimeter(self):
        pass

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        return 3.14159 * self.radius ** 2

    def perimeter(self):
        return 2 * 3.14159 * self.radius

class Rectangle(Shape):
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

    def perimeter(self):
        return 2 * (self.width + self.height)

shapes = [Circle(5), Rectangle(4, 6)]
for shape in shapes:
    print(f"Area: {shape.area()}, Perimeter: {shape.perimeter()}")

class ClassName:
    # 1. Class variable — shared across all instances
    species = "Homo sapiens"

    # 2. Constructor — called when an object is created
    def __init__(self, name, age):
        # 3. Instance variables — unique to each object
        self.name = name
        self.age = age

    # 4. Instance method — acts on a specific object
    def greet(self):
        return f"Hi, I'm {self.name}, age {self.age}."

    # 5. Class method — acts on the class itself, not an instance
    @classmethod
    def get_species(cls):
        return cls.species

    # 6. Static method — no access to class or instance, just a utility
    @staticmethod
    def is_adult(age):
        return age >= 18

    # 7. String representation
    def __repr__(self):
        return f"Person(name={self.name}, age={self.age})"

class Engine:
    def __init__(self, horsepower):
        self.horsepower = horsepower

    def start(self):
        return f"Engine with {self.horsepower}hp started."

class Car:
    def __init__(self, brand, horsepower):
        self.brand = brand
        self.engine = Engine(horsepower)  # composition

    def drive(self):
        return f"{self.brand}: {self.engine.start()} Let's go!"

my_car = Car("Toyota", 150)
print(my_car.drive())
# Toyota: Engine with 150hp started. Let's go!

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    def __add__(self, other):       # supports v1 + v2
        return Vector(self.x + other.x, self.y + other.y)

    def __len__(self):              # supports len(v)
        return int((self.x**2 + self.y**2) ** 0.5)

    def __eq__(self, other):        # supports v1 == v2
        return self.x == other.x and self.y == other.y

v1 = Vector(2, 3)
v2 = Vector(4, 1)
print(v1 + v2)   # Vector(6, 4)
print(len(v1))   # 3
print(v1 == v2)  # False

class Tool:
    def __init__(self, name, description):
        self.name = name
        self.description = description

    def run(self, input_text):
        raise NotImplementedError

class SearchTool(Tool):
    def run(self, input_text):
        return f"[Search results for: {input_text}]"

class CalculatorTool(Tool):
    def run(self, input_text):
        try:
            return str(eval(input_text))
        except Exception:
            return "Invalid expression"

class Agent:
    def __init__(self, tools):
        self.tools = {tool.name: tool for tool in tools}

    def use_tool(self, tool_name, input_text):
        tool = self.tools.get(tool_name)
        if tool:
            return tool.run(input_text)
        return "Tool not found."

agent = Agent(tools=[SearchTool("search", "Web search"), CalculatorTool("calc", "Math")])
print(agent.use_tool("calc", "3 * (7 + 2)"))   # 27
print(agent.use_tool("search", "OOP in Python")) # [Search results for: OOP in Python]

# WRONG — all instances share the same list
class Bag:
    def __init__(self, items=[]):
        self.items = items

# CORRECT
class Bag:
    def __init__(self, items=None):
        self.items = items if items is not None else []

class Counter:
    count = 0  # class variable

    def increment(self):
        self.count += 1  # creates an instance variable, shadows class variable
